\begin{theorem}
The Taylor expansion of $y_n$ given by \eqref{eq:311b} and \eqref{eq:311c} is equal to
\[
y_n = y(x_0) + \sum_{i=1}^n h^i \xi_i \sum_{t \in T_i} \frac{1}{\sigma(t)\gamma(t)} F(t)(y(x_0)) + O(h^{n+1}). \tag{311d}
\]
\end{theorem}

